script:
frappe.ui.form.on('Daily Work Logs', {

    refresh: function(frm) {
        if (!frm.doc.intern) {
            frappe.db.get_list("Intern", {
                filters: {
                    user: frappe.session.user
                },
                fields: ["name", "mentor"],
                limit: 1
            }).then(function(records) {
                if (records.length > 0) {
                    frm.set_value("intern", records[0].name);
                    frm.set_value("mentor", records[0].mentor);
                }
            });
        }
    }

});

frappe.listview_settings["Daily Work Log"] = {
    onload(listview) {
        // Only apply restrictions for Mentor role
        if (!frappe.user.has_role("Mentor")) return;

        // Restrict the Intern filter field to only show assigned interns
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Intern",
                filters: { mentor: ["in", [frappe.session.user]] },
                fields: ["name", "intern_name"],
                limit: 50
            },
            callback(r) {
                if (!r.message) return;
                // Store for use in filter rendering
                listview.assigned_interns = r.message.map(i => i.name);
            }
        });
    }
};

frappe.listview_settings["Daily Work Logs"] = {
    get_indicator(doc) {
        if (doc.is_late && doc.status === "Submitted") {
            return ["Late", "orange", "is_late,=,1"];
        }
        if (doc.status === "Approved") {
            return ["Approved", "green"];
        }
        if (doc.status === "Rejected") {
            return ["Rejected", "red"];
        }
        if (doc.status === "Reviewed") {
            return ["Reviewed", "blue"];
        }
        return ["Submitted", "grey"];
    }
};

frappe.ui.form.on("Intern", {
    refresh(frm) {
        // 1. Show warning banner if attendance is low
        if (frm.doc.low_attendance) {
            frm.dashboard.add_comment(
                `⚠️ Low Attendance: ${frm.doc.attendance_percentage}% — Below 75% threshold`,
                "red",
                true
            );
        }

        // 2. Trigger the data fetch and heatmap rendering
        render_attendance_heatmap(frm);
    }
});

function render_attendance_heatmap(frm) {
    // Fetch the last 100 attendance records for this specific intern
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Intern Attendance",
            filters: { intern: frm.doc.name },
            fields: ["date", "status"],
            limit: 100
        },
        callback: function(r) {
            let data = r.message || [];
            draw_heatmap(frm, data);
        }
    });
}

function draw_heatmap(frm, data) {
    let attendance_map = {};
    data.forEach(d => {
        attendance_map[d.date] = d.status;
    });

    let today = frappe.datetime.now_date();

    // --- STREAK CALCULATOR LOGIC ---
    let current_streak = 0;
    for (let i = 0; i < 60; i++) {
        let check_date_str = frappe.datetime.add_days(today, -i);
        let check_date_obj = frappe.datetime.str_to_obj(check_date_str);
        let status = attendance_map[check_date_str];

        if (status === "Present") {
            current_streak++;
        } else if (check_date_obj.getDay() === 0) {
            // getDay() === 0 means Sunday. Skip it without breaking the streak.
            continue;
        } else {
            // If today isn't marked yet, don't penalize them and break the past streak.
            if (i === 0 && !status) continue;
            
            // Any other missed day breaks the streak.
            break;
        }
    }
    // -------------------------------

    let heatmap_html = `
        <div style="margin-top: 15px; padding: 20px; border: 1px solid var(--border-color); border-radius: 8px; background: transparent;">
            
            <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px;">
                <h6 style="margin: 0; color: var(--text-color); font-weight: 600;">Last 60 Days Activity</h6>
                <span style="background: rgba(255, 153, 0, 0.1); color: #ff9900; padding: 4px 10px; border-radius: 12px; font-size: 12px; font-weight: bold; border: 1px solid rgba(255, 153, 0, 0.3);">
                    🔥 Current Streak: ${current_streak} Days
                </span>
            </div>

            <div style="display: flex; flex-wrap: wrap; gap: 5px;">
    `;

    let start_date = frappe.datetime.add_days(today, -60);

    // Draw the 60 boxes
    for (let i = 0; i <= 60; i++) {
        // THESE ARE THE TWO LINES YOU ACCIDENTALLY DELETED:
        let current_date = frappe.datetime.add_days(start_date, i);
        let status = attendance_map[current_date];

        // Format the date for the tooltip
        let formatted_date = frappe.datetime.str_to_user(current_date);

        let color = "var(--control-bg)"; 
        let border = "1px solid var(--border-color)";
        let tooltip = `${formatted_date} — No Record`;

        if (status === "Present") {
            color = "#39d353"; 
            border = "1px solid #2ea043";
            tooltip = `${formatted_date} — Present`;
        } else if (status === "Absent") {
            color = "#f85149"; 
            border = "1px solid #da3633";
            tooltip = `${formatted_date} — Absent`;
        }

        heatmap_html += `
            <div title="${tooltip}" style="
                width: 16px;
                height: 16px;
                background-color: ${color};
                border-radius: 3px;
                border: ${border};
                cursor: pointer;
                transition: transform 0.1s ease;
            " onmouseover="this.style.transform='scale(1.2)'" onmouseout="this.style.transform='scale(1)'"></div>
        `;
    }

    // Legend
    heatmap_html += `
            </div>
            <div style="margin-top: 16px; display: flex; gap: 15px; font-size: 12px; color: var(--text-muted); font-weight: 500;">
                <div style="display: flex; align-items: center; gap: 6px;">
                    <div style="width: 12px; height: 12px; background: #39d353; border-radius: 2px;"></div> Present
                </div>
                <div style="display: flex; align-items: center; gap: 6px;">
                    <div style="width: 12px; height: 12px; background: #f85149; border-radius: 2px;"></div> Absent
                </div>
                <div style="display: flex; align-items: center; gap: 6px;">
                    <div style="width: 12px; height: 12px; background: var(--control-bg); border: 1px solid var(--border-color); border-radius: 2px;"></div> No Record
                </div>
            </div>
        </div>
    `;

    // Inject into the HTML field
    $(frm.fields_dict.attendance_heatmap.wrapper).html(heatmap_html);
}

frappe.ui.form.on("Daily Work Logs", {
    refresh(frm) {
        render_skill_tags(frm);
    },
    after_save(frm) {
        render_skill_tags(frm);
    }
});

function render_skill_tags(frm) {
    // Remove previous tags wrapper if exists
    $(frm.fields_dict.skills.wrapper).find('.skill-tags-wrapper').remove();

    const skills = frm.doc.skills || [];
    if (!skills.length) return;

    // Build tag chips HTML
    let tags_html = '<div class="skill-tags-wrapper" style="display:flex;flex-wrap:wrap;gap:6px;margin-top:8px;">';
    
    skills.forEach(row => {
        if (row.skill) {
            tags_html += `
                <span style="
                    background:#e8f4fd;
                    color:#185fa5;
                    border:0.5px solid #85b7eb;
                    border-radius:20px;
                    padding:4px 12px;
                    font-size:12px;
                    font-weight:500;
                ">${row.skill}</span>`;
        }
    });

    tags_html += '</div>';

    // Inject below the skills table
    $(frm.fields_dict.skills.wrapper).append(tags_html);
}
